/* Ejemplos de búsquedas lineales y búsqueda binaria iterativa.
 *
 *
 */
#include <iostream>
#include <vector>
using namespace std;

//Búsquedas

/* Entrada:
 *    un vector de números enteros: ¿Puede ser vacío? ¿Tiene que ser de un tamaño concreto? ¿Importa si es de enteros?
 *    un valor: ¿tiene que existir? ¿importa si es un entero?
 * Salida:
 *   una posición: ¿Qué valores puede tener? ¿Y si el valor no está?
 */

int busqueda1(const vector<int>& v, int valor) {
    int i = 0, pos = -1; //índice y posición que devolvemos
    while (i < v.size()) {
        if (valor == v[i]) {
            pos = i;
        }
        i++;
    }
    return pos;
}

int busqueda2(const vector<int>& v, int valor) {
    int i = 0, pos = -1; //índice y posición que devolvemos
    bool encontrado = false;
    while (i < v.size() && !encontrado) {
        if (valor == v[i]) {
            encontrado = true;
            pos = i;
        }
        i++;
    }
    return pos;
}

int busqueda3(const vector<int>& v, int valor) {
    int i = 0;
    while (i < v.size() && valor != v[i])
        ++i;
    return i;
}

// ¿Y si nos restringimos a vectores ordenados? ¿Se puede hacer algo más?
// Devolver la posición en la que debería ir el elemento si no está.

pair<bool, int> busqueda4(const vector<int>& v, int valor) {
    int i = 0;
    while (i < v.size() && valor > v[i])
        ++i;
    return {!v.empty() && valor == v[i], i};
}

//Pero si está ordenado parece innecesario mirar todos los valores.

pair<bool,int> busqueda_binaria1(const vector<int>& v, int valor){
    int pos;
    bool encontrado = false;
    int i = 0, f = (int)v.size(); //Buscamos en [i, f)
    while (i < f && !encontrado) {
        int m = (f + i) / 2; //calculamos el punto medio
        if (v[m] == valor) {//lo hemos encontrado
            encontrado = true;
            pos = m;
        } else {//No está en m
            if (v[m] < valor)//el valor es mayor, buscamos por la derecha [m+1, f)
                i = m + 1;
            else //el valor es más pequeño buscamos por la izquierda [i, m)
                f = m;
        }
    }
    if(!encontrado)
        pos = i;

    return {encontrado, pos};
}


pair<bool, int> busqueda_binaria2(const vector<int>& v, int valor) {
    int i = 0;
    int f = v.size(); //Buscamos en [i, f)

    while (i < f) {
        int m = (i + f) / 2; // buscamos el punto medio

        if (v[m] < valor)
            i = m + 1; //El elemento estará a la derecha [m+1, f)
        else //v[m] >= valor
            f = m;   // Seguimos buscando en el intervalo [i, m).
    }
    //Al final del bucle, i apunta al primer elemento que es >= valor
    return {i < v.size() && v[i] == valor, i};
}

//Intervalo [i, f)
pair<bool, int> busqueda_binaria_rec(const vector<int>& v, int valor, int i, int f){
    if(i >= f){// Caso base: un valor o ninguno
        return {i < v.size() && v[i] == valor, i};
    }
    else{//Caso recursivo: al menos un elemento
        int m = (i + f) / 2; //punto medio
        if(v[m] < valor)//hay que buscar por la derecha
            return busqueda_binaria_rec(v, valor, m + 1, f);
        else // caso v[m] >= valor: buscamos por la izquierda. Incluído el m
            return busqueda_binaria_rec(v, valor, i, m);
    }
}

pair<bool, int> busqueda_binaria3(const vector<int>& v, int valor) {
    return busqueda_binaria_rec(v, valor, 0, v.size());
}


int main(){
    vector<int> v = {10, 2, 1, -2, 3, 1, 6};
    int elemento = -2;

    cout << "Primer algoritmo: "  << busqueda1(v, elemento) << "\n";
    cout << "Segundo algoritmo: " << busqueda2(v, elemento) << "\n";
    cout << "Tercer algoritmo: "  << busqueda3(v, elemento) << "\n";

    vector<int> v_ord = {-2, 1, 2, 2, 2, 3,3,3,3,3,3,3,3, 10};
    elemento = 2;
    pair<bool,int> sol = busqueda4(v_ord, elemento);
    cout << "Cuarto algoritmo: ";
    if (sol.first)
        cout << sol.second << "\n";
    else
        cout << "El valor no está, pero iría en la posición " << sol.second <<"\n";

    sol = busqueda_binaria1(v_ord, elemento);
    cout << "Búsqueda binaria 1: ";
    if (sol.first)
        cout << sol.second << "\n";
    else
        cout << "El valor no está, pero iría en la posición " << sol.second <<"\n";

    sol = busqueda_binaria2(v_ord, elemento);
    cout << "Búsqueda binaria 2: ";
    if (sol.first)
        cout << sol.second << "\n";
    else
        cout << "El valor no está, pero iría en la posición " << sol.second <<"\n";

    sol = busqueda_binaria3(v_ord, elemento);
