#include <iostream>
#include <vector>
using namespace std;

/* ******************************************************************* */
/* ************************* Quicksort ******************************* */
struct par{
    int a, b;
};

/*
 * [ini, a) son menores que el pivote
 * [a, b] iguales al pivote
 * [b+1, fin] mayores que el pivote
 */
par particion(vector<int>& v, int ini, int fin){
    int pivote = v[ini];  //elegimos el primer valor como pivote
    int k = ini, a = ini, b = fin;  //variable, a y b

    while(k <= b){
        /* [ini, a)   menores
         * [a,k)      iguales
         * [b+1, fin] mayores
         */
        if(v[k] == pivote)
            ++k;
        else if(v[k] < pivote) {
            swap(v[k], v[a]);
            ++a;
            ++k;
        }
        else{ //v[k] > pivote
            swap(v[k], v[b]);
            --b;
        }
    }
    return {a, b};
}

//Intervalo [ini, fin]
void quickSort(vector<int>& v, int ini, int fin){
    if (ini < fin){ //hay más de un elemento
        par indices = particion(v, ini, fin);
        quickSort(v,ini,indices.a-1);
        quickSort(v,indices.b+1, fin);
    }
}

void quickSort(vector<int>& v){
    quickSort(v,0,v.size()-1);
}

/* ******************************************************************* */
/* ************************* Mergesort ******************************* */

void mezcla(vector<int>& v, int ini, int m, int fin) {
    int i = ini, j = m + 1; //índices para recorrer v desde [ini, m] y (m, fin]
    vector<int> aux(fin - ini + 1); //vector auxiliar para mezclar
    int k = 0; //índice para aux
    while (i <= m && j <= fin) {
        if (v[i] < v[j]) {
            aux[k] = v[i];
            ++k; ++i;
        } else if (v[i] > v[j]) {
            aux[k] = v[j];
            ++k; ++j;
        } else {//v[i] == v[j]
            aux[k] = v[i];
            ++k; ++i;
            aux[k] = v[j];
            ++k; ++j;
        }
    }
    //Lo que queda
    while (i <= m) {
        aux[k] = v[i];
        ++k; ++i;
    }
    while (j <= fin) {
        aux[k] = v[j];
        ++k; ++j;
    }
    k = 0; //actualizamos el trozo de v
    for (int a = ini; a <= fin; ++a) {
        v[a] = aux[k]; ++k;
    }
}

void mergesort(vector<int>& v, int ini, int fin){
    if(ini < fin){
        int m = (fin + ini)/2;
        mergesort(v, ini, m);
        mergesort(v, m+1, fin);
        mezcla(v, ini, m, fin);
    }
}

void mergesort(vector<int>& v){
    mergesort(v, 0, v.size()-1);
}


/* ******************************************************************* */
/* ***************** Ordenación por inserción ************************ */

void ordInsercion(vector<int>& v, int c, int f) {
    for (int i = c+1; i <= f; i++) {
        int elemento = v[i], j = i - 1; //elemento a colocar e índice para explorar su lugar
        while (j >= c && elemento < v[j]) {
            v[j + 1] = v[j];
            --j;
        }
        v[j + 1] = elemento;
    }
}

void ordInsercion(vector<int>& v){
    ordInsercion(v, 0, (int)v.size()-1);
}


/* ******************************************************************* */
/* ***************** Ordenación de la burbuja ************************ */

void burbuja(vector<int>& v, int c, int f){
    for (int i = c; i < f - 1; ++i)
        for (int j = c; j < f - i - 1; j++)
            if(v[j] > v[j+1])
                swap(v[j], v[j+1]);
}

void burbuja(vector<int>& v){
    burbuja(v, 0, (int)v.size());
}



